965	static ngx_int_t
966	ngx_init_zone_pool(ngx_cycle_t *cycle, ngx_shm_zone_t *zn)
967	{
968	    u_char           *file;
969	    ngx_slab_pool_t  *sp;
970	
971	    sp = (ngx_slab_pool_t *) zn->shm.addr;
972	
973	    if (zn->shm.exists) {
974	
975	        if (sp == sp->addr) {
976	            return NGX_OK;
977	        }
978	
979	#if (NGX_WIN32)
980	
981	        /* remap at the required address */
982	
983	        if (ngx_shm_remap(&zn->shm, sp->addr) != NGX_OK) {
984	            return NGX_ERROR;
985	        }
986	
987	        sp = (ngx_slab_pool_t *) zn->shm.addr;
988	
989	        if (sp == sp->addr) {
990	            return NGX_OK;
991	        }
992	
993	#endif
994	
995	        ngx_log_error(NGX_LOG_EMERG, cycle->log, 0,
996	                      "shared zone \"%V\" has no equal addresses: %p vs %p",
997	                      &zn->shm.name, sp->addr, sp);
998	        return NGX_ERROR;
999	    }
1000	
1001	    sp->end = zn->shm.addr + zn->shm.size;
1002	    sp->min_shift = 3;
1003	    sp->addr = zn->shm.addr;
1004	
1005	#if (NGX_HAVE_ATOMIC_OPS)
1006	
1007	    file = NULL;
1008	
1009	#else
1010	
1011	    file = ngx_pnalloc(cycle->pool,
1012	                       cycle->lock_file.len + zn->shm.name.len + 1);
1013	    if (file == NULL) {
1014	        return NGX_ERROR;
1015	    }
1016	
1017	    (void) ngx_sprintf(file, "%V%V%Z", &cycle->lock_file, &zn->shm.name);
1018	
1019	#endif
1020	
1021	    if (ngx_shmtx_create(&sp->mutex, &sp->lock, file) != NGX_OK) {
1022	        return NGX_ERROR;
1023	    }
1024	
1025	    ngx_slab_init(sp);
1026	
1027	    return NGX_OK;
1028	}
